class Player{public static void main(String[]a){var s=new java.util.Scanner(System.in);var h=s.nextLine().split(" ");var e=new java.util.HashMap<String,String>();e.put(h[3],h[4]);for(int i=Integer.parseInt(h[7]);i-->0;){var l=s.nextLine().split(" ");e.put(l[0],l[1]);}for(;;){var l=s.nextLine().split(" ");var t=e.getOrDefault(l[0],l[1]);System.out.println(l[0].charAt(0)==45||l[1].equals(t)||(l[2].compareTo("N")>0)==(Integer.parseInt(l[1])<Integer.parseInt(t))?"WAIT":"BLOCK");}}}